usort($collection, function ($a, $b) {
                        $ratingA = isset($a['saswp_review_rating']) ? (float) $a['saswp_review_rating'] : 0;
                        $ratingB = isset($b['saswp_review_rating']) ? (float) $b['saswp_review_rating'] : 0;

                        if ($ratingA == $ratingB) {
                            return 0;
                        }

                        return ($ratingA > $ratingB) ? 1 : -1; // ASC
                    })

